import React from 'react';
import { Event } from '../types';

interface EventsCardProps {
	events: Event[];
	loading?: boolean;
	error?: string | null;
}

const EventsCard: React.FC<EventsCardProps> = ({ events, loading, error }) => {
	if (loading) {
		return (
			<div className="bg-white rounded-lg shadow-lg p-8">
				<div className="flex items-center justify-center py-8">
					<div className="animate-spin rounded-full h-8 w-8 border-b-2 border-uncc-green mr-3"></div>
					<span className="text-gray-600">Loading events...</span>
				</div>
			</div>
		);
	}

	if (error) {
		return (
			<div className="bg-white rounded-lg shadow-lg p-8">
				<div className="bg-red-100 border-l-4 border-red-500 text-red-700 p-4 rounded">
					{error}
				</div>
			</div>
		);
	}

	if (events.length === 0) {
		return (
			<div className="bg-white rounded-lg shadow-lg p-8 text-center">
				<div className="text-4xl mb-4">🎭</div>
				<h3 className="text-xl font-semibold text-gray-700 mb-2">No Events Found</h3>
				<p className="text-gray-500">Try searching for different events or locations.</p>
			</div>
		);
	}

	return (
		<div className="bg-white rounded-lg shadow-lg p-8">
			<h2 className="text-2xl font-bold text-uncc-green mb-6">Upcoming Events</h2>
			<div className="space-y-4 max-h-96 overflow-y-auto">
				{events.slice(0, 5).map((event) => (
					<div key={event.id} className="border-b border-gray-200 pb-4 last:border-b-0">
						<div className="flex items-start space-x-4">
							{event.image_url && (
								<img
									src={event.image_url}
									alt={event.name}
									className="w-16 h-16 object-cover rounded-lg flex-shrink-0"
								/>
							)}
							<div className="flex-1 min-w-0">
								<h3 className="text-lg font-semibold text-gray-800 truncate">
									{event.name}
								</h3>
								<div className="text-sm text-gray-600 mt-1">
									{event.date && (
										<span className="mr-2">
											📅 {new Date(event.date).toLocaleDateString()}
										</span>
									)}
									{event.time && (
										<span className="mr-2">
											🕐 {event.time}
										</span>
									)}
								</div>
								<div className="text-sm text-gray-600 mt-1">
									{event.venue && (
										<span className="mr-2">
											🏟️ {event.venue}
										</span>
									)}
									{event.city && (
										<span>📍 {event.city}</span>
									)}
								</div>
								{event.price_min && event.price_max && (
									<div className="text-sm text-green-600 mt-1 font-medium">
										💰 ${event.price_min} - ${event.price_max}
									</div>
								)}
								{event.url && (
									<a
										href={event.url}
										target="_blank"
										rel="noopener noreferrer"
										className="text-sm text-uncc-green hover:underline mt-1 inline-block"
									>
										Get Tickets →
									</a>
								)}
							</div>
						</div>
					</div>
				))}
			</div>
			{events.length > 5 && (
				<div className="text-center mt-4">
					<span className="text-sm text-gray-500">
						Showing 5 of {events.length} events
					</span>
				</div>
			)}
		</div>
	);
};

export default EventsCard;
